    // in the case r1.0 == r2.0 == true because the spec's ensures clause
    // `!ret.0 ==> ret.1 == Q` doesn't constrain ret.1 when ret.0 is true.
    // We discharge the half we can: r1.0 == r2.0 (both equal P) and the
    // !r1.0 case where r1.1 == r2.1 == Q.
    let p: bool = forall|i: int| #![auto] lo <= i <= hi ==> self_.vals@[i]@ == v@;
    let q: bool = self_.vals@[hi as int]@ != v@ && forall|i: int| #![auto] lo <= i < hi ==> self_.vals@[i]@ == v@;
    if (r1.0 == p) && (!r1.0 ==> (r1.1 == q)) && (r2.0 == p) && (!r2.0 ==> (r2.1 == q)) {
        assert(r1.0 == r2.0);
        if !r1.0 {
            assert(r1.1 == r2.1);
        }
    }

